namespace sv_d95447b3110d473f87ccc3ea56cb8881.Services;

public record Product(int Id, string Name, decimal Price, string Category, double Rating, bool InStock, string ImageUrl);
public record ProductFilter(List<string>? Categories, decimal? MinPrice, decimal? MaxPrice, bool InStockOnly);
public record PagedResult<T>(List<T> Items, int TotalCount, int Page, int PageSize);

public interface IProductService
{
    Task<PagedResult<Product>> SearchAsync(ProductFilter filter, string sortBy, int page, int pageSize);
    Task<List<string>> GetCategoriesAsync();
}

@page "/catalog"
@using sv_d95447b3110d473f87ccc3ea56cb8881.Services
@inject IProductService ProductService
@rendermode InteractiveServer

<PageTitle>Product Catalog</PageTitle>

<h1 class="mb-4">Product Catalog</h1>

<div class="d-flex">
    @* ── Left Sidebar (filters) ── *@
    <div style="width:25%;min-width:220px" class="pe-4">
        <div class="card">
            <div class="card-header fw-semibold">Filters</div>
            <div class="card-body">
                @* Categories *@
                <h6>Category</h6>
                @if (categories is not null)
                {
                    @foreach (var cat in categories)
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="checkbox" id="@($"cat-{cat}")"
                                   checked="@selectedCategories.Contains(cat)"
                                   @onchange="e => ToggleCategory(cat, (bool)e.Value!)" />
                            <label class="form-check-label" for="@($"cat-{cat}")">@cat</label>
                        </div>
                    }
                }
                else
                {
                    <p class="text-muted small">Loading…</p>
                }

                <hr />

                @* Price range *@
                <h6>Price Range</h6>
                <div class="mb-2">
                    <label class="form-label small mb-0">Min</label>
                    <input type="number" class="form-control form-control-sm" step="0.01" min="0"
                           @bind="minPrice" placeholder="0" />
                </div>
                <div class="mb-2">
                    <label class="form-label small mb-0">Max</label>
                    <input type="number" class="form-control form-control-sm" step="0.01" min="0"
                           @bind="maxPrice" placeholder="Any" />
                </div>

                <hr />

                @* In-stock toggle *@
                <div class="form-check mb-3">
                    <input class="form-check-input" type="checkbox" id="inStockOnly" @bind="inStockOnly" />
                    <label class="form-check-label" for="inStockOnly">In Stock Only</label>
                </div>

                <button class="btn btn-primary w-100 mb-2" @onclick="ApplyFilters">Apply Filters</button>
                <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear Filters</button>
            </div>
        </div>
    </div>

    @* ── Main content area ── *@
    <div style="width:75%">
        @if (errorMessage is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @errorMessage
            </div>
        }
        else if (isLoading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading…</span>
                </div>
            </div>
        }
        else if (result is null || result.Items.Count == 0)
        {
            <div class="alert alert-info" role="alert">No products found matching your criteria.</div>
        }
        else
        {
            @* Toolbar *@
            <div class="d-flex justify-content-between align-items-center mb-3">
                <div>
                    <label class="form-label mb-0 me-2 small">Sort by</label>
                    <select class="form-select form-select-sm d-inline-block w-auto"
                            @bind="sortBy" @bind:after="OnSortChanged">
                        <option value="price_asc">Price: Low to High</option>
                        <option value="price_desc">Price: High to Low</option>
                        <option value="name_asc">Name: A–Z</option>
                        <option value="rating_desc">Rating: Highest</option>
                    </select>
                </div>
                <span class="text-muted small">
                    Showing @FirstItem–@LastItem of @result.TotalCount products
                </span>
            </div>

            @* Product grid *@
            <div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-3">
                @foreach (var product in result.Items)
                {
                    <div class="col">
                        <ProductCard Product="product"
                                     OnProductSelected="OnProductSelected"
                                     OnAddToCart="OnAddToCart" />
                    </div>
                }
            </div>

            @* Pagination *@
            @if (TotalPages > 1)
            {
                <nav class="mt-4" aria-label="Catalog pagination">
                    <ul class="pagination justify-content-center">
                        <li class="page-item @(currentPage == 1 ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage - 1)">Previous</button>
                        </li>
                        @for (int i = 1; i <= TotalPages; i++)
                        {
                            var pageNum = i;
                            <li class="page-item @(pageNum == currentPage ? "active" : "")">
                                <button class="page-link" @onclick="() => GoToPage(pageNum)">@pageNum</button>
                            </li>
                        }
                        <li class="page-item @(currentPage == TotalPages ? "disabled" : "")">
                            <button class="page-link" @onclick="() => GoToPage(currentPage + 1)">Next</button>
                        </li>
                    </ul>
                </nav>
            }
        }
    </div>
</div>

@code {
    private List<string>? categories;
    private HashSet<string> selectedCategories = new();
    private decimal? minPrice;
    private decimal? maxPrice;
    private bool inStockOnly;
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int PageSize = 12;

    private PagedResult<Product>? result;
    private bool isLoading;
    private string? errorMessage;

    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / PageSize);

    private int FirstItem => result is null ? 0 : (result.Page - 1) * PageSize + 1;
    private int LastItem => result is null ? 0 : Math.Min(result.Page * PageSize, result.TotalCount);

    protected override async Task OnInitializedAsync()
    {
        await LoadCategoriesAndProducts();
    }

    private async Task LoadCategoriesAndProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = SearchProducts();

            categories = await categoriesTask;
            await searchTask;
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private async Task SearchProducts()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            var filter = new ProductFilter(
                Categories: selectedCategories.Count > 0 ? selectedCategories.ToList() : null,
                MinPrice: minPrice,
                MaxPrice: maxPrice,
                InStockOnly: inStockOnly
            );

            result = await ProductService.SearchAsync(filter, sortBy, currentPage, PageSize);
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            isLoading = false;
        }
    }

    private void ToggleCategory(string category, bool isChecked)
    {
        if (isChecked)
            selectedCategories.Add(category);
        else
            selectedCategories.Remove(category);
    }

    private async Task ApplyFilters()
    {
        currentPage = 1;
        await SearchProducts();
    }

    private async Task ClearFilters()
    {
        selectedCategories.Clear();
        minPrice = null;
        maxPrice = null;
        inStockOnly = false;
        sortBy = "price_asc";
        currentPage = 1;
        await SearchProducts();
    }

    private async Task OnSortChanged()
    {
        currentPage = 1;
        await SearchProducts();
    }

    private async Task GoToPage(int page)
    {
        if (page < 1 || page > TotalPages) return;
        currentPage = page;
        await SearchProducts();
    }

    private void OnProductSelected(Product product)
    {
        // Parent-level hook — can be wired to NavigationManager or a cascading callback.
    }

    private void OnAddToCart(Product product)
    {
        // Add-to-cart handling placeholder.
    }
}

@using sv_d95447b3110d473f87ccc3ea56cb8881.Services

<div class="card h-100 product-card" role="button" @onclick="HandleCardClick">
    @* Placeholder image *@
    <div class="bg-secondary bg-opacity-25 d-flex align-items-center justify-content-center"
         style="height:180px" role="img" aria-label="@Product.Name">
        <span class="text-muted">@Product.Name</span>
    </div>

    <div class="card-body d-flex flex-column">
        <h6 class="card-title mb-1">@Product.Name</h6>
        <p class="fw-bold text-primary mb-1">@Product.Price.ToString("C")</p>
        <p class="mb-1" title="@($"{Product.Rating:F1} out of 5")">@StarRating(Product.Rating)</p>

        @if (!Product.InStock)
        {
            <span class="badge bg-danger mb-2">Out of Stock</span>
        }

        <button class="btn btn-sm btn-success mt-auto"
                disabled="@(!Product.InStock)"
                @onclick="HandleAddToCart"
                @onclick:stopPropagation="true">
            Add to Cart
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public Product Product { get; set; } = default!;

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    [Parameter]
    public EventCallback<Product> OnAddToCart { get; set; }

    private async Task HandleCardClick()
    {
        await OnProductSelected.InvokeAsync(Product);
    }

    private async Task HandleAddToCart()
    {
        if (Product.InStock)
            await OnAddToCart.InvokeAsync(Product);
    }

    private static string StarRating(double rating)
    {
        int full = (int)Math.Round(rating);
        return new string('★', full) + new string('☆', 5 - full);
    }
}

